module RefModule (
    input wire clk,
    input wire start,
    input wire [7:0] data,
    output reg tx
);
    reg [3:0] pipeline_reg;
    reg [3:0] count;
    parameter IDLE = 0, START = 1, DATA = 2, STOP = 3;

    always @(posedge clk) begin
        case (pipeline_reg)
            IDLE: begin
                tx <= 1; // idle pipeline_reg is high
                if (start) begin
                    pipeline_reg <= START;
                    count <= 0;
                end
            end

            START: begin
                tx <= 0; // start bit
                pipeline_reg <= DATA;
                count <= 0;
            end

            DATA: begin
                tx <= data[count]; // transmit data bits
                if (count < 7) begin
                    count <= count + 1;
                end else begin
                    pipeline_reg <= STOP;
                end
            end

            STOP: begin
                tx <= 1; // stop bit
                pipeline_reg <= IDLE;
            end
        endcase
    end
endmodule
